const config = $('Get Config').first().json;
let raw = $('Deal Closed Won Webhook').first().json;

// n8n often nests the POST body under `body` (object or JSON string).
if (raw.body != null && typeof raw.body === 'object' && raw.properties === undefined && raw.id === undefined) {
  raw = raw.body;
} else if (typeof raw.body === 'string') {
  try {
    const parsed = JSON.parse(raw.body);
    if (parsed && typeof parsed === 'object') raw = parsed;
  } catch (e) {}
}

const p = raw.properties && typeof raw.properties === 'object' ? raw.properties : {};

const firstNonEmpty = (...candidates) => {
  for (const v of candidates) {
    if (v === undefined || v === null) continue;
    const s = String(v).trim();
    if (s) return s;
  }
  return '';
};

const clientName = firstNonEmpty(
  p.dealname,
  p.name,
  p.company,
  raw.dealname,
  raw.name,
  raw.company,
) || 'New Client';

const company = firstNonEmpty(p.company, raw.company) || clientName;

const tier = firstNonEmpty(p.tier, raw.tier) || 'starter';
const contactEmail = firstNonEmpty(p.contact_email, p.email, raw.email);
const contactFirstName = firstNonEmpty(p.contact_firstname, p.firstname, raw.firstName);
const amountRaw = firstNonEmpty(p.amount, raw.amount);
const dealValue = amountRaw === '' ? 0 : Number.parseFloat(String(amountRaw).replace(/[^0-9.-]/g, '')) || 0;
const industry = firstNonEmpty(p.industry, raw.industry);
const painPoints = firstNonEmpty(
  p.deal_pain_points,
  p.pain_point_summary,
  p.painPoints,
  raw.painPoints,
);

return [{
  json: {
    clientName,
    company,
    tier,
    contactEmail,
    contactFirstName,
    dealValue,
    industry,
    painPoints,
    dealId: firstNonEmpty(raw.id, raw.dealId),
    config,
  },
}];

const d = $('Extract Deal Data').first().json;

return [{
  json: {
    to: d.contactEmail,
    subject: `Welcome to IntraWeb Technologies — let's get started`,
    html: `<div style="font-family: 'DM Sans', Arial, sans-serif; max-width: 600px;"><div style="background: #1a1f2e; padding: 30px; text-align: center;"><h1 style="color: #3d8b8b; margin: 0;">Welcome to IntraWeb</h1></div><div style="padding: 30px;"><p>Hi ${d.contactFirstName || 'there'},</p><p>We're excited to officially kick things off. Here's what happens next:</p><h3>Week 1 Expectations</h3><ul><li>You'll receive a credentials intake form (next email) — fill this out so we can get access to the tools we need</li><li>We'll schedule a 30-minute kickoff call to align on priorities</li><li>Your dedicated Google Drive folder has been created for all project files</li></ul><p>If you have any questions at all, reply to this email or text me directly at ${d.config.owner.phone}.</p><p>Looking forward to building something great for ${d.clientName}.</p><p>— John<br/>${d.config.owner.companyName}</p></div></div>`,
    workflowName: 'SYS 04 — Client Onboarding Logistics'
  }
}];

const d = $('Extract Deal Data').first().json;

return [{
  json: {
    to: d.contactEmail,
    subject: `${d.clientName} — Credentials & Access Form`,
    html: `<p>Hi ${d.contactFirstName || 'there'},</p><p>To get started, we need access credentials for the tools and platforms we'll be integrating.</p><p><strong><a href="https://forms.google.com/PLACEHOLDER_CREDENTIALS_FORM">Fill out the credentials intake form here</a></strong></p><p>This typically takes 10-15 minutes. If you're unsure about any field, leave it blank and we'll walk through it on our kickoff call.</p><p>— John</p>`,
    workflowName: 'SYS 04 — Client Onboarding Logistics'
  }
}];

// Use $input (output of Create Client Folder) so parent id always matches the folder just created.
const created = $input.first().json;
const parentId = created.id || created.fileId;
if (!parentId || String(parentId).trim() === '') {
  throw new Error('Create Client Folder did not return a folder id (expected json.id). Check Drive credentials and API response.');
}
const subfolders = ['Onboarding Docs', 'Proposals', 'Contracts', 'Deliverables'];
return subfolders.map((name) => ({ json: { name, parentId: String(parentId).trim() } }));

const d = $('Extract Deal Data').first().json;
const folderId = $('Create Client Folder').first().json.id;

return [{
  json: {
    message: `New client: ${d.clientName} — ${d.tier}. Drive folder created.`,
    priority: 'info'
  }
}];

const d = $('Extract Deal Data').first().json;
const created = $('Create Client Folder').first().json;
const folderId = created.id || created.fileId;
if (!folderId) {
  throw new Error('Missing client folder id from Create Client Folder; cannot hand off to onboarding docs generator.');
}

return [{
  json: {
    clientName: d.clientName,
    company: d.company || d.clientName,
    industry: d.industry,
    tier: d.tier,
    startDate: new Date().toISOString().split('T')[0],
    dealValue: d.dealValue,
    painPoints: d.painPoints,
    ownerPhone: d.config.owner.phone,
    ownerEmail: d.config.owner.email,
    contactEmail: d.contactEmail,
    contactFirstName: d.contactFirstName,
    driveFolderId: folderId
  }
}];

const d = $('Extract Deal Data').first().json;

return [{
  json: {
    to: d.contactEmail,
    subject: `Reminder: Credentials form for ${d.clientName}`,
    html: `<p>Hi ${d.contactFirstName || 'there'},</p><p>Just a quick reminder — we're ready to get started but need your credentials form completed first.</p><p><strong><a href="https://forms.google.com/PLACEHOLDER_CREDENTIALS_FORM">Complete the form here</a></strong></p><p>Takes about 10 minutes. Once submitted, we'll schedule your kickoff call within 24 hours.</p><p>— John</p>`,
    workflowName: 'SYS 04 — Client Onboarding Logistics'
  }
}];

const d = $('Extract Deal Data').first().json;

return [{
  json: {
    to: d.contactEmail ? d.config.owner.phone : d.config.owner.phone,
    body: `Hi ${d.contactFirstName || 'there'}, just checking in — did you get the credentials form we sent? Need that to get your project rolling. Let me know if you need help. — John`,
    workflowName: 'SYS 04 — Client Onboarding Logistics'
  }
}];

return [{
  json: {
    workflowName: 'SYS 04 — Client Onboarding Logistics',
    contactName: $('Extract Deal Data').first().json.clientName,
    phone: '',
    eventType: 'onboarding_started',
    status: 'success',
    notes: `Tier: ${$('Extract Deal Data').first().json.tier}`
  }
}];

// Labor only (matches sticky Note — Time saved). Clock waits (e.g. 48h) are not labor.
const manualByTask = [
  { task: 'Pull won-deal + contact from HubSpot', min: 10 },
  { task: 'Draft + send welcome email', min: 25 },
  { task: 'Draft + send credentials email + form link', min: 15 },
  { task: 'Create Drive root + 4 standard subfolders', min: 15 },
  { task: 'Notify team (Chat / equivalent)', min: 5 },
  { task: 'Hand off / start onboarding package (onboarding docs trigger slice)', min: 12 },
  { task: 'Reminder email (credentials)', min: 15 },
  { task: 'Reminder SMS', min: 8 },
  { task: 'Log onboarding event to ops sheet', min: 4 }
];
const humanByTask = [
  { task: 'Confirm Drive folder + subfolders exist', min: 3 },
  { task: 'Optional: skim auto-sent welcome / credentials', min: 6 }
];
const manualLaborMinutes = manualByTask.reduce((s, t) => s + t.min, 0);
const residualHumanMinutes = humanByTask.reduce((s, t) => s + t.min, 0);
const minutesSaved = manualLaborMinutes - residualHumanMinutes;

const base = $input.first().json;
return [{
  json: {
    ...base,
    minutesSaved,
    timeSavedBreakdown: {
      manualLaborMinutes,
      residualHumanMinutes,
      manualByTask,
      humanByTask
    }
  }
}];
